using System.ComponentModel.DataAnnotations;

namespace UniversityCourseCatalog.Services;

public class Department
{
    public int Id { get; set; }
    public string Name { get; set; } = "";
    public string Description { get; set; } = "";
}

public class Course
{
    public int Id { get; set; }
    public int DepartmentId { get; set; }
    public string Title { get; set; } = "";
    public string Description { get; set; } = "";
    public int Credits { get; set; }
    public string Schedule { get; set; } = "";
    public string InstructorName { get; set; } = "";
    public string InstructorBio { get; set; } = "";
    public bool IsFeatured { get; set; }
}

public class EnrollmentRequest
{
    [Required(ErrorMessage = "Name is required.")]
    public string Name { get; set; } = "";

    [Required(ErrorMessage = "Student ID is required.")]
    public string StudentId { get; set; } = "";

    [Required(ErrorMessage = "Please select a course.")]
    [Range(1, int.MaxValue, ErrorMessage = "Please select a course.")]
    public int CourseId { get; set; }

    public DateTime SubmittedAt { get; set; }
}

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Course> _courses;
    private readonly List<EnrollmentRequest> _enrollments = new();

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Name = "Computer Science", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Name = "Mathematics", Description = "Study of numbers, structures, and patterns." },
            new() { Id = 3, Name = "Physics", Description = "Study of matter, energy, and the fundamental forces of nature." }
        };

        _courses = new List<Course>
        {
            new() { Id = 1, DepartmentId = 1, Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using C#. Covers variables, control flow, functions, and object-oriented principles.", Credits = 3, Schedule = "Mon/Wed 9:00-10:30 AM", InstructorName = "Dr. Alice Chen", InstructorBio = "PhD in Computer Science from MIT with 15 years of teaching experience.", IsFeatured = true },
            new() { Id = 2, DepartmentId = 1, Title = "Data Structures and Algorithms", Description = "Study of fundamental data structures including arrays, linked lists, trees, and graphs. Algorithm analysis and design techniques.", Credits = 4, Schedule = "Tue/Thu 11:00 AM-12:30 PM", InstructorName = "Dr. Bob Martinez", InstructorBio = "Researcher in algorithm optimization with publications in top conferences.", IsFeatured = false },
            new() { Id = 3, DepartmentId = 1, Title = "Web Development", Description = "Modern web development with HTML, CSS, JavaScript, and server-side frameworks. Build full-stack applications.", Credits = 3, Schedule = "Mon/Wed/Fri 2:00-3:00 PM", InstructorName = "Prof. Carol Davis", InstructorBio = "Former software engineer at major tech companies with 10 years of industry experience.", IsFeatured = true },
            new() { Id = 4, DepartmentId = 2, Title = "Calculus I", Description = "Limits, derivatives, and integrals of single-variable functions. Applications to physics and engineering.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00-11:00 AM", InstructorName = "Dr. David Kim", InstructorBio = "Award-winning mathematics educator and author of popular calculus textbooks.", IsFeatured = true },
            new() { Id = 5, DepartmentId = 2, Title = "Linear Algebra", Description = "Vector spaces, matrices, linear transformations, eigenvalues, and applications.", Credits = 3, Schedule = "Tue/Thu 1:00-2:30 PM", InstructorName = "Dr. Elena Volkov", InstructorBio = "Specialist in applied mathematics with focus on computational methods.", IsFeatured = false },
            new() { Id = 6, DepartmentId = 2, Title = "Probability and Statistics", Description = "Introduction to probability theory, random variables, distributions, and statistical inference.", Credits = 3, Schedule = "Mon/Wed 3:00-4:30 PM", InstructorName = "Dr. Frank Johnson", InstructorBio = "Statistician with extensive experience in data science and biostatistics.", IsFeatured = false },
            new() { Id = 7, DepartmentId = 3, Title = "Physics I: Mechanics", Description = "Classical mechanics including kinematics, Newton's laws, energy, momentum, and rotational motion.", Credits = 4, Schedule = "Tue/Thu 9:00-10:30 AM", InstructorName = "Dr. Grace Lee", InstructorBio = "Experimental physicist specializing in particle physics research.", IsFeatured = true },
            new() { Id = 8, DepartmentId = 3, Title = "Electromagnetism", Description = "Electric fields, magnetic fields, Maxwell's equations, and electromagnetic waves.", Credits = 4, Schedule = "Mon/Wed/Fri 1:00-2:00 PM", InstructorName = "Dr. Henry Wilson", InstructorBio = "Theoretical physicist with research in quantum electrodynamics.", IsFeatured = false }
        };
    }

    public List<Department> GetDepartments() => _departments;

    public List<Course> GetCourses(string? search, int? departmentId)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(search))
            query = query.Where(c =>
                c.Title.Contains(search, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(search, StringComparison.OrdinalIgnoreCase));

        return query.ToList();
    }

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public void SubmitEnrollment(EnrollmentRequest request)
    {
        request.SubmittedAt = DateTime.Now;
        _enrollments.Add(request);
    }

    public string? GetDepartmentName(int departmentId) =>
        _departments.FirstOrDefault(d => d.Id == departmentId)?.Name;
}

