@page "/courses"
@inject UniversityCourseCatalog.Services.CatalogService CatalogService

<PageTitle>Courses - State University Course Catalog</PageTitle>

<h1>Course Catalog</h1>

<form method="get" action="courses">
    <div class="row mb-3">
        <div class="col-md-5">
            <input type="text" name="search" value="@Search" class="form-control" placeholder="Search courses..." />
        </div>
        <div class="col-md-4">
            <select name="departmentId" class="form-select">
                <option value="">All Departments</option>
                @foreach (var dept in CatalogService.GetDepartments())
                {
                    <option value="@dept.Id" selected="@(DepartmentId == dept.Id)">@dept.Name</option>
                }
            </select>
        </div>
        <div class="col-md-3">
            <button type="submit" class="btn btn-primary">Search</button>
        </div>
    </div>
</form>

@{
    var courses = CatalogService.GetCourses(Search, DepartmentId);
}

@if (courses.Any())
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Title</th>
                <th>Department</th>
                <th>Credits</th>
                <th>Schedule</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var course in courses)
            {
                <tr>
                    <td><a href="courses/@course.Id">@course.Title</a></td>
                    <td>@CatalogService.GetDepartmentName(course.DepartmentId)</td>
                    <td>@course.Credits</td>
                    <td>@course.Schedule</td>
                </tr>
            }
        </tbody>
    </table>
}
else
{
    <p>No courses found matching your criteria.</p>
}

@code {
    [SupplyParameterFromQuery]
    public string? Search { get; set; }

    [SupplyParameterFromQuery]
    public int? DepartmentId { get; set; }
}

@page "/courses/{Id:int}"
@inject UniversityCourseCatalog.Services.CatalogService CatalogService

<PageTitle>@(course?.Title ?? "Course") - State University Course Catalog</PageTitle>

@if (course is null)
{
    <h1>Course Not Found</h1>
    <p>The requested course could not be found.</p>
}
else
{
    <h1>@course.Title</h1>
    <dl class="row">
        <dt class="col-sm-3">Department</dt>
        <dd class="col-sm-9">@CatalogService.GetDepartmentName(course.DepartmentId)</dd>

        <dt class="col-sm-3">Description</dt>
        <dd class="col-sm-9">@course.Description</dd>

        <dt class="col-sm-3">Credits</dt>
        <dd class="col-sm-9">@course.Credits</dd>

        <dt class="col-sm-3">Schedule</dt>
        <dd class="col-sm-9">@course.Schedule</dd>

        <dt class="col-sm-3">Instructor</dt>
        <dd class="col-sm-9">@course.InstructorName</dd>

        <dt class="col-sm-3">Instructor Bio</dt>
        <dd class="col-sm-9">@course.InstructorBio</dd>
    </dl>

    <a href="enroll?courseId=@course.Id" class="btn btn-success me-2">Enroll in this Course</a>
    <a href="courses" class="btn btn-secondary">Back to Course List</a>
}

@code {
    [Parameter]
    public int Id { get; set; }

    private Course? course;

    protected override void OnInitialized()
    {
        course = CatalogService.GetCourse(Id);
    }
}

@page "/enroll"
@inject UniversityCourseCatalog.Services.CatalogService CatalogService

<PageTitle>Enroll - State University Course Catalog</PageTitle>

<h1>Course Enrollment</h1>

@if (submitted)
{
    <div class="alert alert-success">
        <h4>Enrollment Submitted!</h4>
        <p>Thank you, <strong>@Model.Name</strong>. Your enrollment request for the selected course has been submitted successfully.</p>
        <a href="courses" class="btn btn-primary">Back to Courses</a>
    </div>
}
else
{
    <EditForm method="post" Model="Model" OnValidSubmit="HandleSubmit" FormName="enrollment" Enhance>
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />
        <AntiforgeryToken />

        <div class="mb-3">
            <label for="name" class="form-label">Name</label>
            <InputText id="name" @bind-Value="Model.Name" class="form-control" />
            <ValidationMessage For="() => Model.Name" />
        </div>

        <div class="mb-3">
            <label for="studentId" class="form-label">Student ID</label>
            <InputText id="studentId" @bind-Value="Model.StudentId" class="form-control" />
            <ValidationMessage For="() => Model.StudentId" />
        </div>

        <div class="mb-3">
            <label for="courseId" class="form-label">Course</label>
            <InputSelect id="courseId" @bind-Value="Model.CourseId" class="form-select">
                <option value="0">-- Select a course --</option>
                @foreach (var course in CatalogService.GetCourses(null, null))
                {
                    <option value="@course.Id">@course.Title</option>
                }
            </InputSelect>
            <ValidationMessage For="() => Model.CourseId" />
        </div>

        <button type="submit" class="btn btn-primary">Submit Enrollment</button>
    </EditForm>
}

@code {
    [SupplyParameterFromForm]
    public EnrollmentRequest Model { get; set; } = new();

    [SupplyParameterFromQuery]
    public int? CourseId { get; set; }

    private bool submitted;

    protected override void OnInitialized()
    {
        if (CourseId.HasValue && Model.CourseId == 0)
        {
            Model.CourseId = CourseId.Value;
        }
    }

    private void HandleSubmit()
    {
        CatalogService.SubmitEnrollment(Model);
        submitted = true;
    }
}

